  return (
    <footer
      style={{
        background: "#0f172a",
        color: "white",
        padding: "40px 0",
        marginTop: "60px"
      }}
    >
      <div className="container text-center">

        <h4>
          Book A Doctor
        </h4>

        <p>
          Healthcare Appointment
          Booking Platform
        </p>

        <p>
          📧 support@bookadoctor.com
        </p>

        <p>
          © 2026 All Rights Reserved
        </p>

      </div>
    </footer>
  );
}

export default Footer;
